class LogViewerController < ApplicationController
  before_action :authenticate_admin_user!

  def show
    log_filename = params[:log]

    log_dir = Rails.root.join('log').to_s
    requested_path = File.expand_path(File.join(log_dir, log_filename.to_s))

    unless requested_path.starts_with?(log_dir) && File.file?(requested_path)
      render plain: "Error: Log file not found or unauthorized access.", status: :not_found
      return
    end

    begin
      @log_content = File.read(requested_path)
      render plain: @log_content, content_type: 'text/plain'
    rescue Errno::ENOENT
      render plain: "Error: Log file '#{log_filename}' does not exist.", status: :not_found
    rescue => e
      Rails.logger.error "Failed to read log file '#{requested_path}': #{e.message}"
      render plain: "Error reading log file: #{e.message}", status: :internal_server_error
    end
  end

  private

  def authenticate_admin_user!
    unless current_user_is_admin?
      head :forbidden
    end
  end

  def current_user_is_admin?
    # Replace this with your actual admin user check.
    # Example: `current_user && current_user.admin?`
    # Example: `session[:admin_logged_in]`
    # By default, it returns false, making the controller secure by default.
    false
  end
end